
// Code generated by Prompty emitter; DO NOT EDIT.

use agentschema::ParserConfig;


#[test]
fn test_parser_config_load_json() {
    let json = r####"
{
  "kind": "prompty",
  "options": {
    "key": "value"
  }
}
"####;
    let result = ParserConfig::from_json(json);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
}

#[test]
fn test_parser_config_load_yaml() {
    let yaml = r####"
kind: prompty
options:
  key: value

"####;
    let result = ParserConfig::from_yaml(yaml);
    assert!(result.is_ok(), "Failed to load from YAML: {:?}", result.err());
}

#[test]
fn test_parser_config_roundtrip() {
    let json = r####"
{
  "kind": "prompty",
  "options": {
    "key": "value"
  }
}
"####;
    let result = ParserConfig::from_json(json);
    assert!(result.is_ok(), "Failed to load: {:?}", result.err());
}



#[test]
fn test_parser_config_from_parser() {
    let value = serde_json::json!("example");
    let instance = ParserConfig::load_from_value(&value);
    let _ = instance; // abstract type, load succeeded
}


